import{_ as n}from"./plugin-vue_export-helper-c27b6911.js";import{o as s,c as a,f as e}from"./app-e7c604ce.js";const t="/my-docs/assets/fx-form-9e45183f.jpg",o={},p=e('<h3 id="场景" tabindex="-1"><a class="header-anchor" href="#场景" aria-hidden="true">#</a> 场景</h3><ol><li>资源管理、数据统计都需要用到比如车辆管理、仪器管理等管理模块，维护数据、出入库数据一般都是表格显示，并且配套一些条件过滤与分页</li><li>封装一个<code>form</code>组件，有<code>input select timerange</code>等搜索条件。下面是<code>table</code>组件，表格内容可以根据form组件传入的条件等变化</li></ol><h3 id="解决方案" tabindex="-1"><a class="header-anchor" href="#解决方案" aria-hidden="true">#</a> 解决方案</h3><ol><li>实现主要是对<code>elementui</code>的常用组件的二次封装。</li><li>form组件包含了elementui的<code>input select timerange radio</code>组件，根据传入的配置显示组件用了动态组件。</li><li>table组件的多级表头、表头和表格内容区域都可以进行自定义是用了递归以及插槽，根据传入的配置显示表格。</li></ol><h3 id="实现" tabindex="-1"><a class="header-anchor" href="#实现" aria-hidden="true">#</a> 实现</h3><ol><li>数据结构<code>formConfig tableConfig</code>如何设计？</li><li><code>fx_form</code>组件需要先定义<code>fx_input fx_select fx_timerange fx_radio</code>几个通用组件，然后定义<code>fx_form</code>文件 <ul><li>在里面props接收传入的配置数组以及<code>v-for</code>遍历，<code>&lt;component :is=&quot;type&quot;&gt;</code>根据通过:is属性动态切换渲染哪个需要的子组件。</li></ul></li><li><code>fx_table</code>组件，多级表头且可以自定义标题，需要定义<code>columnItem</code>子组件 <ul><li>多级表头：表格列组件需要进行递归，所以这里主要解决了<code>递归+插槽嵌套</code>的问题。如果传入的列数组有<code>children</code>说明有下一级数据，则递归使用自己，生成多级表头</li><li>表头和表格内容自定义：通过列的<code>slotName headerProp</code>配置</li><li>页码封装、数据请求：通过传入的动态配置项(查询参数)以及请求接口去请求；watch会观察到查询参数变化就重新请求</li></ul></li><li><code>form组件</code>的输入框进行搜索如何影响<code>table内容</code>显示 <ul><li>页码变化或者fx_form一些表单查询条件的变化一般作用在动态配置项上，检测到变化了就重新请求<br><img src="'+t+`" alt="image.png" loading="lazy"></li></ul></li></ol><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// formConfig 根据传入的配置显示组件用了动态组件</span>
formConfig <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token punctuation">{</span>
    propName<span class="token punctuation">,</span>
    <span class="token literal-property property">type</span><span class="token operator">:</span> <span class="token string">&#39;fx-input&#39;</span><span class="token punctuation">,</span>
    size<span class="token punctuation">,</span>
    defaultValue<span class="token punctuation">,</span>
    clearable<span class="token punctuation">,</span>
    <span class="token punctuation">}</span><span class="token punctuation">,</span><span class="token punctuation">{</span>
    propName<span class="token punctuation">,</span>
    <span class="token literal-property property">type</span><span class="token operator">:</span> <span class="token string">&#39;fx-select&#39;</span><span class="token punctuation">,</span>
    size<span class="token punctuation">,</span>
    clearable<span class="token punctuation">,</span>
    multiple<span class="token punctuation">,</span>
    <span class="token literal-property property">loadmore</span><span class="token operator">:</span> <span class="token boolean">true</span><span class="token punctuation">,</span>
    defaultValue<span class="token punctuation">,</span>
    filterable<span class="token punctuation">,</span>
    <span class="token function">getInitData</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span><span class="token punctuation">}</span><span class="token comment">//写接口       </span>
<span class="token punctuation">}</span><span class="token punctuation">]</span>
<span class="token comment">// tableConfig 根据传入的配置显示表格，有children说明是多级表单</span>
tableConfig <span class="token operator">=</span>  <span class="token punctuation">{</span>
  <span class="token literal-property property">border</span><span class="token operator">:</span> <span class="token boolean">false</span><span class="token punctuation">,</span> <span class="token comment">// 表格样式配置</span>
  <span class="token literal-property property">columns</span><span class="token operator">:</span> <span class="token punctuation">[</span>     <span class="token comment">//自定义列 是一个数组</span>
    <span class="token punctuation">{</span> <span class="token literal-property property">prop</span><span class="token operator">:</span> <span class="token string">&quot;ID&quot;</span><span class="token punctuation">,</span><span class="token literal-property property">label</span><span class="token operator">:</span> <span class="token string">&quot;ID&quot;</span><span class="token punctuation">,</span><span class="token literal-property property">width</span><span class="token operator">:</span> <span class="token string">&quot;120&quot;</span><span class="token punctuation">,</span><span class="token punctuation">}</span><span class="token punctuation">,</span>
    <span class="token punctuation">{</span> <span class="token literal-property property">prop</span><span class="token operator">:</span> <span class="token string">&quot;Name&quot;</span><span class="token punctuation">,</span><span class="token literal-property property">label</span><span class="token operator">:</span><span class="token string">&quot;名字&quot;</span><span class="token punctuation">,</span><span class="token literal-property property">width</span><span class="token operator">:</span> <span class="token string">&quot;320&quot;</span><span class="token punctuation">,</span> <span class="token literal-property property">slotName</span><span class="token operator">:</span> <span class="token string">&#39;MethodName&#39;</span><span class="token punctuation">,</span> <span class="token literal-property property">headerProp</span><span class="token operator">:</span> <span class="token string">&quot;stateHeader&quot;</span> <span class="token punctuation">}</span><span class="token punctuation">,</span>  <span class="token comment">//自定义表头slot值,</span>
    <span class="token punctuation">{</span> <span class="token literal-property property">prop</span><span class="token operator">:</span> <span class="token string">&#39;title&#39;</span><span class="token punctuation">,</span><span class="token literal-property property">label</span><span class="token operator">:</span> <span class="token string">&#39;书名&#39;</span><span class="token punctuation">,</span>
      <span class="token literal-property property">children</span><span class="token operator">:</span> <span class="token punctuation">[</span><span class="token punctuation">{</span><span class="token literal-property property">prop</span><span class="token operator">:</span> <span class="token string">&#39;author&#39;</span><span class="token punctuation">,</span> <span class="token literal-property property">label</span><span class="token operator">:</span> <span class="token string">&#39;作者&#39;</span><span class="token punctuation">}</span> <span class="token punctuation">,</span><span class="token punctuation">{</span><span class="token literal-property property">prop</span><span class="token operator">:</span> <span class="token string">&#39;readCount&#39;</span><span class="token punctuation">,</span> <span class="token literal-property property">label</span><span class="token operator">:</span> <span class="token string">&#39;阅读数&#39;</span><span class="token punctuation">}</span><span class="token punctuation">]</span>
    <span class="token punctuation">}</span><span class="token punctuation">]</span><span class="token punctuation">,</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="难点" tabindex="-1"><a class="header-anchor" href="#难点" aria-hidden="true">#</a> 难点</h3><ol><li>有些组件交互复杂，甚至由多个子组件构成，它们之间的通信和状态共享如何处理？ <ul><li>多级组件嵌套需要传递数据时，通常使用的方法是通过vuex。如果仅仅是传递数据，而不做中间处理，使用 vuex 处理，这就有点大材小用了 <ul><li>解决：使用<code>$attrs/$listeners</code>;数据与事件的传递：数据是通过<code>v-bind=&quot;$attrs&quot;</code>，事件是通过<code>v-on=&quot;$listeners&quot;</code>传递。</li></ul></li><li>数据处理：业务组件-&gt; fx-form组件-&gt;子组件，数据属性如何显示得到具体input\\select上？ <ul><li>解决：孙到子如何传递，就是<code>中间fx_form</code>的动态组件<code>v-bind=&quot;item&quot;</code>属性继承业务组件传过来的配置属性;孙子组件据是通过<code>v-bind=&quot;$attrs&quot;</code>，继承原有组件所有的v-bind属性</li></ul></li><li>事件处理：如孙子组件select变化，搜索框变化，点击搜索等等，事件如何传递给上级组件？ <ul><li>解决：使用事件<code>$listeners&quot;</code>透传给最外层的业务组件。fx_form的动态组件<code>v-on=&quot;$listeners&quot;</code>继承业务组件所有v-on的事件，fx_form的子组件如fx-input触发自定义事件时候，业务组件的fx_form可以感应得到数据变化然后通知给fx_table了</li></ul></li></ul></li><li>fx_form组件的子组件<code>el-select</code>组件可以远程数据，并且触底懒加载。主要是使用指令实现 <ul><li>很多select数据并不是固定死的，而是需要接口获取的。业务组件可以配置<code>getInitData</code>方法,具体fx-select组件调用传递过来的远程搜索方法，拿到对应的选项值</li><li>有些数据比较多，为了显示不卡顿，那么需要触底懒加载。主要使用指令去封装<code>v-select-loadmore=&quot;debounce(loadMore)&quot;</code></li></ul></li><li>fx_table组件表头和表格内容区域都可以进行自定义，就是需要用到插槽。多层级的插槽还会涉及到透传 <ul><li>具体页面为父页面，表格组件为子页面，表格列组件<code>TableColumn</code>为孙子组件，在父页面中使用了插槽，并且插槽放置了内容，在孙子组件中是获取不到的。</li><li>所以需要用到作用域插槽<code>$scopedSlots</code>透传。让TableColumn可以获取到具体页面传递的插槽内容。</li></ul></li></ol>`,9),l=[p];function c(i,r){return s(),a("div",null,l)}const k=n(o,[["render",c],["__file","组件库之组件实例2.html.vue"]]);export{k as default};
